import { applyTags, saveFileDirectly, isTagWritingSupported } from './utils/audioUtils';
import { ProcessingState, AudioFile } from './types';
import { findDuplicateSets } from './utils/duplicateUtils';
import { exportFilesToCsv } from './utils/csvUtils';

declare const JSZip: any;
declare const saveAs: any;
declare const uuid: { v4: () => string; };

const SUPPORTED_FORMATS = ['audio/mpeg', 'audio/mp3', 'audio/mp4', 'audio/flac', 'audio/wav', 'audio/ogg', 'audio/m4a', 'audio/x-m4a', 'audio/aac', 'audio/x-ms-wma'];

type ModalState = 
  | { type: 'none' }
  | { type: 'settings' }
  | { type: 'rename' }
  | { type: 'batch-edit' }
  | { type: 'post-download'; count: number }
  | { type: 'preview-changes'; title: string; confirmationText: string; previews: any[]; onConfirm: () => void; }
  | { type: 'import' }
  | { type: 'duplicates'; sets: Map<string, AudioFile[]> }
  | { type: 'xml-converter' }
  | { type: 'smart-playlist' }
  | { type: 'smart-tagger'; fileId: string };

async function* getFilesRecursively(entry: any, path = ''): AsyncGenerator<{ file: File, handle: any, path: string }> {
    if (entry.kind === 'file') {
        try {
            const file = await entry.getFile();
            const lowerName = file.name.toLowerCase();
            const hasAudioExt = ['.mp3', '.wav', '.flac', '.ogg', '.m4a', '.aac', '.wma'].some(ext => lowerName.endsWith(ext));

            if (SUPPORTED_FORMATS.includes(file.type) || hasAudioExt) {
                yield { file, handle: entry, path: path + entry.name };
            }
        } catch (e) {
            console.warn(`Nie udało się odczytać pliku: ${entry.name}`, e);
        }
    } else if (entry.kind === 'directory') {
        const newPath = path + entry.name + '/';
        try {
            for await (const handle of entry.values()) {
                yield* getFilesRecursively(handle, newPath);
            }
        } catch (e) {
            console.warn(`Nie udało się otworzyć katalogu: ${entry.name}`, e);
        }
    }
}

