                    onClearAll={() => { if(confirm('Wyczyścić bibliotekę?')) { setFiles([]); addToast('Wyczyszczono bibliotekę', 'success'); }}}
                    onRename={() => setModalState({ type: 'rename' })}
                    onFindDuplicates={handleFindDuplicates}
