## components/ErrorBoundary.tsx

Nowy komponent do wyłapywania błędów krytycznych w aplikacji.

```tsx
import React, { Component, ErrorInfo, ReactNode } from 'react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  private handleReset = () => {
    localStorage.clear();
    window.location.reload();
  };

  public render() {
    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-slate-950 text-white p-6 text-center">
          <div className="bg-red-900/20 p-6 rounded-2xl border border-red-800 max-w-md">
            <h1 className="text-2xl font-bold text-red-500 mb-4">Coś poszło nie tak</h1>
            <p className="text-slate-300 mb-4">Aplikacja napotkała krytyczny błąd po aktualizacji.</p>
            <pre className="bg-black/50 p-3 rounded text-xs text-left overflow-auto max-h-32 mb-6 text-red-300">
              {this.state.error?.message}
            </pre>
            <div className="flex gap-4 justify-center">
                <button 
                    onClick={() => window.location.reload()}
                    className="px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg transition-colors"
                >
                    Odśwież
                </button>
                <button 
                    onClick={this.handleReset}
                    className="px-4 py-2 bg-red-600 hover:bg-red-500 rounded-lg transition-colors"
                >
                    Resetuj ustawienia (Hard Reset)
                </button>
            </div>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
```

