            <pre className="bg-black/50 p-3 rounded text-xs text-left overflow-auto max-h-32 mb-6 text-red-300 font-mono border border-red-900/50">
              {this.state.error?.message}
            </pre>
            <div className="flex gap-4 justify-center">
                <button 
                    onClick={() => window.location.reload()}
                    className="px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg transition-colors font-medium"
                >
                    Odśwież
                </button>
                <button 
                    onClick={this.handleReset}
                    className="px-4 py-2 bg-red-600 hover:bg-red-500 rounded-lg transition-colors font-medium"
                >
                    Resetuj ustawienia
                </button>
            </div>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;
